// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <type_traits>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

// Helper function to map table names to their corresponding types
template<typename T>
struct TableTypeHelper;

// Specializations for each table type
template<>
struct TableTypeHelper<Student> {
    using Type = Student;
    static constexpr auto primary_key = "SNo"_c;
};

template<>
struct TableTypeHelper<Course> {
    using Type = Course;
    static constexpr auto primary_key = "CID"_c;
};

template<>
struct TableTypeHelper<Score> {
    using Type = Score;
    static constexpr auto primary_key = "ScID"_c;
};

template<>
struct TableTypeHelper<Major> {
    using Type = Major;
    static constexpr auto primary_key = "MID"_c;
};

template<typename T>
using TableType = typename TableTypeHelper<T>::Type;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
    // Map table name to corresponding type
    auto conn_result = sqlgen::sqlite::connect(db_path);

    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }

    auto conn = conn_result.value();

    // Use sqlgen's insert functionality
    auto insert_stmt = sqlgen::insert_into<TableType<T>>(records);

    // Execute the insert operation
    auto result = insert_stmt(conn);

    if (!result) {
        throw std::runtime_error("Failed to insert records");
    }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
    // Map table name to corresponding type
    auto conn_result = sqlgen::sqlite::connect(db_path);

    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }

    auto conn = conn_result.value();

    // Determine the table type and primary key
    if (table_name == "Student") {
        auto delete_stmt = sqlgen::delete_from<Student> 
                          | sqlgen::where("SNo"_c == record_id);
        auto result = delete_stmt(conn);
        if (!result) {
            throw std::runtime_error("Failed to delete student record");
        }
    } else if (table_name == "Course") {
        auto delete_stmt = sqlgen::delete_from<Course> 
                          | sqlgen::where("CID"_c == std::stoul(record_id));
        auto result = delete_stmt(conn);
        if (!result) {
            throw std::runtime_error("Failed to delete course record");
        }
    } else if (table_name == "Score") {
        auto delete_stmt = sqlgen::delete_from<Score> 
                          | sqlgen::where("ScID"_c == std::stoul(record_id));
        auto result = delete_stmt(conn);
        if (!result) {
            throw std::runtime_error("Failed to delete score record");
        }
    } else if (table_name == "Major") {
        auto delete_stmt = sqlgen::delete_from<Major> 
                          | sqlgen::where("MID"_c == std::stoul(record_id));
        auto result = delete_stmt(conn);
        if (!result) {
            throw std::runtime_error("Failed to delete major record");
        }
    } else {
        throw std::invalid_argument("Unknown table name: " + table_name);
    }
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const std::string& new_value) {
    auto conn_result = sqlgen::sqlite::connect(db_path);

    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }

    auto conn = conn_result.value();

    // Handle different table types and column types
    if (table_name == "Student") {
        if (col_name == "SNo") {
            auto update_stmt = sqlgen::update<Student>("SNo"_c.set(new_value))
                              | sqlgen::where("SNo"_c == record_id);
            auto result = update_stmt(conn);
            if (!result) {
                throw std::runtime_error("Failed to update student SNo");
            }
        } else if (col_name == "SName") {
            auto update_stmt = sqlgen::update<Student>("SName"_c.set(new_value))
                              | sqlgen::where("SNo"_c == record_id);
            auto result = update_stmt(conn);
            if (!result) {
                throw std::runtime_error("Failed to update student SName");
            }
        } else if (col_name == "Sex") {
            auto update_stmt = sqlgen::update<Student>("Sex"_c.set(std::stoi(new_value)))
                              | sqlgen::where("SNo"_c == record_id);
            auto result = update_stmt(conn);
            if (!result) {
                throw std::runtime_error("Failed to update student Sex");
            }
        }
        // Add other Student columns as needed...

    } else if (table_name == "Course") {
        if (col_name == "CName") {
            auto update_stmt = sqlgen::update<Course>("CName"_c.set(new_value))
                              | sqlgen::where("CID"_c == std::stoul(record_id));
            auto result = update_stmt(conn);
            if (!result) {
                throw std::runtime_error("Failed to update course CName");
            }
        } else if (col_name == "Term") {
            auto update_stmt = sqlgen::update<Course>("Term"_c.set(std::stoi(new_value)))
                              | sqlgen::where("CID"_c == std::stoul(record_id));
            auto result = update_stmt(conn);
            if (!result) {
                throw std::runtime_error("Failed to update course Term");
            }
        }
