    std::string CName;
    std::optional<int> Term = 1;
    std::optional<int> CTime;
    float Credit = 0.0f;
  };

  struct Score {
    sqlgen::ForeignKey<std::string, Student, "SNo"> SNo;
    sqlgen::ForeignKey<int, Course, "CID"> CID;
    std::optional<float> Score;
    sqlgen::PrimaryKey<std::string> SNo_Pk;
    sqlgen::PrimaryKey<int> CID_Pk;
